package com.enterprise.samlsp.model;

import org.springframework.security.core.GrantedAuthority;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.userdetails.UserDetails;

import java.io.Serializable;
import java.util.*;

public class SamlUserDetails implements UserDetails, Serializable {

    private static final long serialVersionUID = 1L;

    private String nameId;
    private String sessionIndex;
    private Map<String, List<String>> attributes;
    private List<GrantedAuthority> authorities;

    public SamlUserDetails(String nameId, String sessionIndex, Map<String, List<String>> attributes) {
        this.nameId = nameId;
        this.sessionIndex = sessionIndex;
        this.attributes = attributes != null ? attributes : new HashMap<>();
        this.authorities = new ArrayList<>();
        this.authorities.add(new SimpleGrantedAuthority("ROLE_USER"));

        List<String> roles = this.attributes.get("roles");
        if (roles != null) {
            for (String role : roles) {
                this.authorities.add(new SimpleGrantedAuthority("ROLE_" + role.toUpperCase()));
            }
        }
    }

    @Override
    public Collection<? extends GrantedAuthority> getAuthorities() { return authorities; }

    @Override
    public String getPassword() { return ""; }

    @Override
    public String getUsername() { return nameId; }

    @Override
    public boolean isAccountNonExpired() { return true; }

    @Override
    public boolean isAccountNonLocked() { return true; }

    @Override
    public boolean isCredentialsNonExpired() { return true; }

    @Override
    public boolean isEnabled() { return true; }

    public String getNameId() { return nameId; }
    public String getSessionIndex() { return sessionIndex; }
    public Map<String, List<String>> getAttributes() { return attributes; }

    public String getFirstAttribute(String name) {
        List<String> values = attributes.get(name);
        return (values != null && !values.isEmpty()) ? values.get(0) : null;
    }

    public String getEmail() { return getFirstAttribute("email"); }
    public String getFirstName() { return getFirstAttribute("firstName"); }
    public String getLastName() { return getFirstAttribute("lastName"); }
    public String getDisplayName() { return getFirstAttribute("displayName"); }
    public String getDepartment() { return getFirstAttribute("department"); }
}

