package com.enterprise.samlsp.service;

import com.enterprise.samlsp.model.SamlAssertion;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.w3c.dom.*;
import org.xml.sax.InputSource;

import javax.xml.XMLConstants;
import javax.xml.crypto.*;
import javax.xml.crypto.dsig.*;
import javax.xml.crypto.dsig.dom.DOMValidateContext;
import javax.xml.crypto.dsig.keyinfo.*;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.*;
import java.security.Key;
import java.security.PublicKey;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;
import java.time.Instant;
import java.util.*;

@Service
public class SamlResponseParser {

    private static final Logger logger = LoggerFactory.getLogger(SamlResponseParser.class);

    private static final String SAML2_PROTOCOL_NS = "urn:oasis:names:tc:SAML:2.0:protocol";
    private static final String SAML2_ASSERTION_NS = "urn:oasis:names:tc:SAML:2.0:assertion";
    private static final String XMLDSIG_NS = "http://www.w3.org/2000/09/xmldsig#";
    private static final String SUCCESS_STATUS = "urn:oasis:names:tc:SAML:2.0:status:Success";

    public Document parseXml(String samlResponseXml) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);

        // Security: Prevent XXE attacks
        factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);

        DocumentBuilder builder = factory.newDocumentBuilder();
        InputSource inputSource = new InputSource(new StringReader(samlResponseXml));
        return builder.parse(inputSource);
    }

    public SamlAssertion extractAssertion(Document document) throws Exception {
        SamlAssertion assertion = new SamlAssertion();

        // Extract Response-level attributes
        Element responseElement = document.getDocumentElement();
        assertion.setDestination(responseElement.getAttribute("Destination"));
        assertion.setInResponseTo(responseElement.getAttribute("InResponseTo"));

        String issueInstantStr = responseElement.getAttribute("IssueInstant");
        if (issueInstantStr != null && !issueInstantStr.isEmpty()) {
            assertion.setIssueInstant(Instant.parse(issueInstantStr));
        }

        // Extract Status
        NodeList statusCodeNodes = responseElement.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "StatusCode");
        if (statusCodeNodes.getLength() > 0) {
            Element statusCodeElement = (Element) statusCodeNodes.item(0);
            assertion.setStatusCode(statusCodeElement.getAttribute("Value"));
        }

        // Extract Response Issuer
        NodeList responseIssuerNodes = responseElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Issuer");
        if (responseIssuerNodes.getLength() > 0) {
            assertion.setIssuer(responseIssuerNodes.item(0).getTextContent().trim());
        }

        // Extract Assertion
        NodeList assertionNodes = responseElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Assertion");
        if (assertionNodes.getLength() == 0) {
            throw new SecurityException("No SAML Assertion found in response");
        }

        Element assertionElement = (Element) assertionNodes.item(0);

        // Extract NameID
        NodeList nameIdNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "NameID");
        if (nameIdNodes.getLength() > 0) {
            Element nameIdElement = (Element) nameIdNodes.item(0);
            assertion.setNameId(nameIdElement.getTextContent().trim());
            assertion.setNameIdFormat(nameIdElement.getAttribute("Format"));
        }

        // Extract SessionIndex from AuthnStatement
        NodeList authnStatementNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AuthnStatement");
        if (authnStatementNodes.getLength() > 0) {
            Element authnStatement = (Element) authnStatementNodes.item(0);
            assertion.setSessionIndex(authnStatement.getAttribute("SessionIndex"));
        }

        // Extract Conditions
        NodeList conditionsNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Conditions");
        if (conditionsNodes.getLength() > 0) {
            Element conditionsElement = (Element) conditionsNodes.item(0);
            String notBefore = conditionsElement.getAttribute("NotBefore");
            String notOnOrAfter = conditionsElement.getAttribute("NotOnOrAfter");

            if (notBefore != null && !notBefore.isEmpty()) {
                assertion.setNotBefore(Instant.parse(notBefore));
            }
            if (notOnOrAfter != null && !notOnOrAfter.isEmpty()) {
                assertion.setNotOnOrAfter(Instant.parse(notOnOrAfter));
            }

            // Extract Audience
            NodeList audienceNodes = conditionsElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Audience");
            if (audienceNodes.getLength() > 0) {
                assertion.setAudience(audienceNodes.item(0).getTextContent().trim());
            }
        }

        // Extract SubjectConfirmationData
        NodeList subjectConfirmationDataNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "SubjectConfirmationData");
        if (subjectConfirmationDataNodes.getLength() > 0) {
            Element scd = (Element) subjectConfirmationDataNodes.item(0);
            assertion.setRecipient(scd.getAttribute("Recipient"));
        }

        // Extract Attributes
        Map<String, List<String>> attributes = extractAttributes(assertionElement);
        assertion.setAttributes(attributes);

        return assertion;
    }

    private Map<String, List<String>> extractAttributes(Element assertionElement) {
        Map<String, List<String>> attributes = new LinkedHashMap<>();

        NodeList attributeStatementNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AttributeStatement");
        if (attributeStatementNodes.getLength() == 0) {
            return attributes;
        }

        Element attributeStatement = (Element) attributeStatementNodes.item(0);
        NodeList attributeNodes = attributeStatement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Attribute");

        for (int i = 0; i < attributeNodes.getLength(); i++) {
            Element attributeElement = (Element) attributeNodes.item(i);
            String name = attributeElement.getAttribute("Name");
            String friendlyName = attributeElement.getAttribute("FriendlyName");

            List<String> values = new ArrayList<>();
            NodeList valueNodes = attributeElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AttributeValue");

            for (int j = 0; j < valueNodes.getLength(); j++) {
                String value = valueNodes.item(j).getTextContent();
                if (value != null) {
                    values.add(value.trim());
                }
            }

            attributes.put(name, values);

            // Also store by friendly name if available
            if (friendlyName != null && !friendlyName.isEmpty()) {
                attributes.put(friendlyName, values);
            }
        }

        return attributes;
    }

    public boolean validateSignature(Document document, X509Certificate idpCertificate) {
        try {
            NodeList signatureNodes = document.getElementsByTagNameNS(XMLDSIG_NS, "Signature");
            if (signatureNodes.getLength() == 0) {
                logger.warn("No XML Signature found in SAML response");
                return false;
            }

            Element signatureElement = (Element) signatureNodes.item(0);

            DOMValidateContext validateContext = new DOMValidateContext(
                    new X509KeySelector(idpCertificate), signatureElement);

            // Important: Set ID attribute resolver for SAML responses
            validateContext.setIdAttributeNS(
                    document.getDocumentElement(), null, "ID");

            NodeList assertionNodes = document.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Assertion");
            for (int i = 0; i < assertionNodes.getLength(); i++) {
                Element assertionEl = (Element) assertionNodes.item(i);
                validateContext.setIdAttributeNS(assertionEl, null, "ID");
            }

            XMLSignatureFactory signatureFactory = XMLSignatureFactory.getInstance("DOM");
            XMLSignature signature = signatureFactory.unmarshalXMLSignature(validateContext);

            boolean valid = signature.validate(validateContext);

            if (!valid) {
                logger.error("SAML response signature validation failed");

                // Debug: Check reference validation
                boolean sv = signature.getSignatureValue().validate(validateContext);
                logger.debug("Signature value validation: {}", sv);

                @SuppressWarnings("unchecked")
                List<Reference> references = signature.getSignedInfo().getReferences();
                for (Reference ref : references) {
                    boolean refValid = ref.validate(validateContext);
                    logger.debug("Reference [{}] validation: {}", ref.getURI(), refValid);
                }
            }

            return valid;
        } catch (Exception e) {
            logger.error("Error validating SAML response signature", e);
            return false;
        }
    }

    private static class X509KeySelector extends KeySelector {
        private final X509Certificate certificate;

        public X509KeySelector(X509Certificate certificate) {
            this.certificate = certificate;
        }

        @Override
        public KeySelectorResult select(KeyInfo keyInfo, Purpose purpose,
                                         AlgorithmMethod method, XMLCryptoContext context) {
            return () -> certificate.getPublicKey();
        }
    }
}

