package com.enterprise.samlsp.service;

import com.enterprise.samlsp.config.SamlConfig;
import com.enterprise.samlsp.model.SamlAssertion;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

import java.time.Duration;
import java.time.Instant;

@Service
public class SamlValidationService {

    private static final Logger logger = LoggerFactory.getLogger(SamlValidationService.class);

    @Autowired
    private SamlConfig samlConfig;

    private static final String SUCCESS_STATUS = "urn:oasis:names:tc:SAML:2.0:status:Success";

    public void validateAssertion(SamlAssertion assertion) throws SecurityException {
        validateStatus(assertion);
        validateIssuer(assertion);
        validateDestination(assertion);
        validateAudience(assertion);
        validateTimestamps(assertion);
        validateNameId(assertion);
        validateRecipient(assertion);
    }

    private void validateStatus(SamlAssertion assertion) {
        if (assertion.getStatusCode() == null || !assertion.getStatusCode().equals(SUCCESS_STATUS)) {
            throw new SecurityException("SAML response status is not Success: " + assertion.getStatusCode());
        }
        logger.debug("Status validation passed");
    }

    private void validateIssuer(SamlAssertion assertion) {
        String expectedIssuer = samlConfig.getIdpEntityId();
        if (expectedIssuer != null && !expectedIssuer.equals(assertion.getIssuer())) {
            throw new SecurityException("SAML response issuer mismatch. Expected: " +
                    expectedIssuer + ", Got: " + assertion.getIssuer());
        }
        logger.debug("Issuer validation passed");
    }

    private void validateDestination(SamlAssertion assertion) {
        String expectedDestination = samlConfig.getAcsUrl();
        if (assertion.getDestination() != null && !assertion.getDestination().isEmpty()) {
            if (!assertion.getDestination().equals(expectedDestination)) {
                throw new SecurityException("SAML response destination mismatch. Expected: " +
                        expectedDestination + ", Got: " + assertion.getDestination());
            }
        }
        logger.debug("Destination validation passed");
    }

    private void validateAudience(SamlAssertion assertion) {
        String expectedAudience = samlConfig.getEntityId();
        if (assertion.getAudience() != null && !assertion.getAudience().isEmpty()) {
            if (!assertion.getAudience().equals(expectedAudience)) {
                throw new SecurityException("SAML audience restriction mismatch. Expected: " +
                        expectedAudience + ", Got: " + assertion.getAudience());
            }
        }
        logger.debug("Audience validation passed");
    }

    private void validateTimestamps(SamlAssertion assertion) {
        Instant now = Instant.now();
        int skewSeconds = samlConfig.getResponseSkewTime();
        Duration skew = Duration.ofSeconds(skewSeconds);

        if (assertion.getNotBefore() != null) {
            Instant adjustedNotBefore = assertion.getNotBefore().minus(skew);
            if (now.isBefore(adjustedNotBefore)) {
                throw new SecurityException("SAML assertion is not yet valid. NotBefore: " +
                        assertion.getNotBefore() + ", Current time: " + now);
            }
        }

        if (assertion.getNotOnOrAfter() != null) {
            Instant adjustedNotOnOrAfter = assertion.getNotOnOrAfter().plus(skew);
            if (now.isAfter(adjustedNotOnOrAfter)) {
                throw new SecurityException("SAML assertion has expired. NotOnOrAfter: " +
                        assertion.getNotOnOrAfter() + ", Current time: " + now);
            }
        }
        logger.debug("Timestamp validation passed");
    }

    private void validateNameId(SamlAssertion assertion) {
        if (assertion.getNameId() == null || assertion.getNameId().isEmpty()) {
            throw new SecurityException("SAML assertion missing NameID");
        }
        logger.debug("NameID validation passed");
    }

    private void validateRecipient(SamlAssertion assertion) {
        String expectedRecipient = samlConfig.getAcsUrl();
        if (assertion.getRecipient() != null && !assertion.getRecipient().isEmpty()) {
            if (!assertion.getRecipient().equals(expectedRecipient)) {
                throw new SecurityException("SAML SubjectConfirmationData recipient mismatch. Expected: " +
                        expectedRecipient + ", Got: " + assertion.getRecipient());
            }
        }
        logger.debug("Recipient validation passed");
    }
}

