package com.enterprise.samlsp.service;

import com.enterprise.samlsp.config.SamlConfig;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.core.io.ClassPathResource;
import org.springframework.stereotype.Service;

import javax.annotation.PostConstruct;
import java.io.InputStream;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;

@Service
public class SamlCertificateService {

    private static final Logger logger = LoggerFactory.getLogger(SamlCertificateService.class);

    @Autowired
    private SamlConfig samlConfig;

    private X509Certificate idpCertificate;

    @PostConstruct
    public void init() {
        try {
            loadIdpCertificate();
        } catch (Exception e) {
            logger.error("Failed to load IdP certificate", e);
            throw new RuntimeException("Failed to load IdP certificate", e);
        }
    }

    private void loadIdpCertificate() throws Exception {
        String certPath = samlConfig.getIdpCertificatePath();
        CertificateFactory cf = CertificateFactory.getInstance("X.509");

        try (InputStream is = new ClassPathResource(certPath).getInputStream()) {
            idpCertificate = (X509Certificate) cf.generateCertificate(is);
            logger.info("Loaded IdP certificate: {}", idpCertificate.getSubjectDN());
        }
    }

    public X509Certificate getIdpCertificate() {
        return idpCertificate;
    }
}

// === SamlAuthenticationService.java ===
package com.enterprise.samlsp.service;

import com.enterprise.samlsp.config.SamlConfig;
import com.enterprise.samlsp.model.SamlAssertion;
import com.enterprise.samlsp.model.SamlUserDetails;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Service;
import org.w3c.dom.Document;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpSession;
import java.nio.charset.StandardCharsets;
import java.util.Base64;
import java.util.Map;
import java.util.Set;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class SamlAuthenticationService {

    private static final Logger logger = LoggerFactory.getLogger(SamlAuthenticationService.class);

    @Autowired
    private SamlResponseParser samlResponseParser;

    @Autowired
    private SamlValidationService samlValidationService;

    @Autowired
    private SamlCertificateService samlCertificateService;

    @Autowired
    private SamlConfig samlConfig;

    // Track processed response IDs to prevent replay attacks
    private final Set<String> processedResponseIds = ConcurrentHashMap.newKeySet();

    public SamlUserDetails processSamlResponse(String samlResponseBase64, HttpServletRequest request)
            throws Exception {

        // Step 1: Decode Base64 SAML Response
        byte[] decodedBytes = Base64.getDecoder().decode(samlResponseBase64);
        String samlResponseXml = new String(decodedBytes, StandardCharsets.UTF_8);
        logger.debug("Decoded SAML Response XML");

        // Step 2: Parse XML
        Document document = samlResponseParser.parseXml(samlResponseXml);
        logger.debug("Parsed SAML Response XML document");

        // Step 3: Check for replay attack
        String responseId = document.getDocumentElement().getAttribute("ID");
        if (responseId != null && !responseId.isEmpty()) {
            if (!processedResponseIds.add(responseId)) {
                throw new SecurityException("Replay attack detected: Response ID already processed: " + responseId);
            }
        }

        // Step 4: Validate XML Signature
        if (samlConfig.isWantAssertionsSigned()) {
            boolean signatureValid = samlResponseParser.validateSignature(
                    document, samlCertificateService.getIdpCertificate());

            if (!signatureValid) {
                throw new SecurityException("SAML response signature validation failed");
            }
            logger.info("SAML response signature validated successfully");
        }

        // Step 5: Extract assertion
        SamlAssertion assertion = samlResponseParser.extractAssertion(document);
        logger.debug("Extracted SAML assertion for NameID: {}", assertion.getNameId());

        // Step 6: Validate assertion
        samlValidationService.validateAssertion(assertion);
        logger.info("SAML assertion validated successfully for user: {}", assertion.getNameId());

        // Step 7: Create user details and session
        SamlUserDetails userDetails = createUserDetails(assertion);
        createAuthenticatedSession(userDetails, request);

        return userDetails;
    }

    private SamlUserDetails createUserDetails(SamlAssertion assertion) {
        return new SamlUserDetails(
                assertion.getNameId(),
                assertion.getSessionIndex(),
                assertion.getAttributes()
        );
    }

    private void createAuthenticatedSession(SamlUserDetails userDetails, HttpServletRequest request) {
        // Invalidate existing session to prevent session fixation
        HttpSession oldSession = request.getSession(false);
        if (oldSession != null) {
            oldSession.invalidate();
        }

        // Create new session
        HttpSession session = request.getSession(true);

        // Store user attributes in session
        session.setAttribute("saml_user", userDetails);
        session.setAttribute("saml_name_id", userDetails.getNameId());
        session.setAttribute("saml_session_index", userDetails.getSessionIndex());

        // Store individual attributes
        Map<String, java.util.List<String>> attributes = userDetails.getAttributes();
        for (Map.Entry<String, java.util.List<String>> entry : attributes.entrySet()) {
            session.setAttribute("saml_attr_" + entry.getKey(), entry.getValue());
        }

        // Store common attributes for easy access
        if (userDetails.getEmail() != null) {
            session.setAttribute("user_email", userDetails.getEmail());
        }
        if (userDetails.getFirstName() != null) {
            session.setAttribute("user_first_name", userDetails.getFirstName());
        }
        if (userDetails.getLastName() != null) {
            session.setAttribute("user_last_name", userDetails.getLastName());
        }
        if (userDetails.getDisplayName() != null) {
            session.setAttribute("user_display_name", userDetails.getDisplayName());
        }
        if (userDetails.getDepartment() != null) {
            session.setAttribute("user_department", userDetails.getDepartment());
        }

        session.setMaxInactiveInterval(samlConfig.getMaxAuthenticationAge());

        // Set Spring Security authentication context
        Authentication authentication = new UsernamePasswordAuthenticationToken(
                userDetails, null, userDetails.getAuthorities());
        SecurityContextHolder.getContext().setAuthentication(authentication);

        logger.info("Created authenticated session for user: {} with session ID: {}",
                userDetails.getNameId(), session.getId());
    }

    public String generateAuthnRequest() {
        String id = "_" + java.util.UUID.randomUUID().toString();
        String issueInstant = java.time.Instant.now().toString();

        String authnRequest = String.format(
                "<?xml version=\"1.0\" encoding=\"UTF-8\"?>" +
                        "<samlp:AuthnRequest xmlns:samlp=\"urn:oasis:names:tc:SAML:2.0:protocol\" " +
                        "xmlns:saml=\"urn:oasis:names:tc:SAML:2.0:assertion\" " +
                        "ID=\"%s\" " +
                        "Version=\"2.0\" " +
                        "IssueInstant=\"%s\" " +
                        "Destination=\"%s\" " +
                        "AssertionConsumerServiceURL=\"%s\" " +
                        "ProtocolBinding=\"urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST\">" +
                        "<saml:Issuer>%s</saml:Issuer>" +
                        "<samlp:NameIDPolicy Format=\"urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress\" " +
                        "AllowCreate=\"true\"/>" +
                        "</samlp:AuthnRequest>",
                id, issueInstant, samlConfig.getIdpSsoUrl(),
                samlConfig.getAcsUrl(), samlConfig.getEntityId()
        );

        return Base64.getEncoder().encodeToString(authnRequest.getBytes(StandardCharsets.UTF_8));
    }
}

// === SamlController.java ===
package com.enterprise.samlsp.controller;

import com.enterprise.samlsp.config.SamlConfig;
import com.enterprise.samlsp.model.SamlUserDetails;
import com.enterprise.samlsp.service.SamlAuthenticationService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.*;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.http.HttpSession;
import java.io.IOException;
import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;

@Controller
public class SamlController {

    private static final Logger logger = LoggerFactory.getLogger(SamlController.class);

    @Autowired
    private SamlAuthenticationService samlAuthenticationService;

    @Autowired
    private SamlConfig samlConfig;

    @GetMapping("/")
    public String home(Model model) {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        if (auth != null && auth.getPrincipal() instanceof SamlUserDetails) {
            SamlUserDetails user = (SamlUserDetails) auth.getPrincipal();
            model.addAttribute("user", user);
            return "home";
        }
        return "redirect:/login";
    }

    @GetMapping("/login")
    public String login() {
        return "login";
    }

    @GetMapping("/saml/login")
    public void initiateLogin(HttpServletResponse response) throws IOException {
        String authnRequest = samlAuthenticationService.generateAuthnRequest();
        String encodedRequest = URLEncoder.encode(authnRequest, StandardCharsets.UTF_8.name());
        String redirectUrl = samlConfig.getIdpSsoUrl() + "?SAMLRequest=" + encodedRequest;

        logger.info("Initiating SAML login, redirecting to IdP: {}", samlConfig.getIdpSsoUrl());
        response.sendRedirect(redirectUrl);
    }

    @PostMapping("/saml/acs")
    public String assertionConsumerService(
            @RequestParam("SAMLResponse") String samlResponse,
            @RequestParam(value = "RelayState", required = false) String relayState,
            HttpServletRequest request,
            Model model) {

        try {
            logger.info("Received SAML Response at ACS endpoint");

            SamlUserDetails userDetails = samlAuthenticationService.processSamlResponse(samlResponse, request);

            logger.info("Successfully authenticated user: {}", userDetails.getNameId());
            model.addAttribute("user", userDetails);

            // Redirect to relay state if provided, otherwise to home
            if (relayState != null && !relayState.isEmpty()) {
                return "redirect:" + relayState;
            }

            return "redirect:/";

        } catch (SecurityException e) {
            logger.error("SAML authentication security error: {}", e.getMessage());
            model.addAttribute("error", "Authentication failed: " + e.getMessage());
            return "error";
        } catch (Exception e) {
            logger.error("SAML authentication error", e);
            model.addAttribute("error", "Authentication processing error: " + e.getMessage());
            return "error";
        }
    }

    @GetMapping("/saml/metadata")
    @ResponseBody
    public String metadata() {
        return String.format(
                "<?xml version=\"1.0\" encoding=\"UTF-8\"?>" +
                        "<md:EntityDescriptor xmlns:md=\"urn:oasis:names:tc:SAML:2.0:metadata\" " +
                        "entityID=\"%s\">" +
                        "<md:SPSSODescriptor AuthnRequestsSigned=\"false\" " +
                        "WantAssertionsSigned=\"%s\" " +
                        "protocolSupportEnumeration=\"urn:oasis:names:tc:SAML:2.0:protocol\">" +
                        "<md:NameIDFormat>urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress</md:NameIDFormat>" +
                        "<md:AssertionConsumerService " +
                        "Binding=\"urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST\" " +
                        "Location=\"%s\" " +
                        "index=\"0\" " +
                        "isDefault=\"true\"/>" +
                        "</md:SPSSODescriptor>" +
                        "</md:EntityDescriptor>",
                samlConfig.getEntityId(),
                samlConfig.isWantAssertionsSigned(),
                samlConfig.getAcsUrl()
        );
    }

    @GetMapping("/profile")
    public String profile(Model model) {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        if (auth != null && auth.getPrincipal() instanceof SamlUserDetails) {
            SamlUserDetails user = (SamlUserDetails) auth.getPrincipal();
            model.addAttribute("user", user);
            model.addAttribute("attributes", user.getAttributes());
            return "profile";
        }
        return "redirect:/login";
    }

    @GetMapping("/logout")
    public String logout(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session != null) {
            logger.info("Logging out user, invalidating session: {}", session.getId());
            session.invalidate();
        }
        SecurityContextHolder.clearContext();
        return "redirect:/login?logout";
    }
}

// === SecurityConfig.java ===
package com.enterprise.samlsp.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configuration.WebSecurityConfigurerAdapter;
import org.springframework.security.web.csrf.CookieCsrfRepository;

@Configuration
@EnableWebSecurity
public class SecurityConfig extends WebSecurityConfigurerAdapter {

    @Override
    protected void configure(HttpSecurity http) throws Exception {
        http
                .authorizeRequests()
                .antMatchers("/login", "/saml/login", "/saml/acs", "/saml/metadata", "/error", "/css/**", "/js/**").permitAll()
                .anyRequest().authenticated()
                .and()
                .formLogin()
                .loginPage("/login")
                .and()
                .logout()
                .logoutUrl("/logout")
                .logoutSuccessUrl("/login?logout")
                .invalidateHttpSession(true)
                .clearAuthentication(true)
                .and()
                .csrf()
                .ignoringAntMatchers("/saml/acs") // SAML ACS must accept POST without CSRF token
                .csrfTokenRepository(CookieCsrfRepository.withHttpOnlyFalse())
                .and()
                .sessionManagement()
                .maximumSessions(1)
                .expiredUrl("/login?expired");
    }
}

// === SamlSessionFilter.java ===
package com.enterprise.samlsp.filter;

import com.enterprise.samlsp.model.SamlUserDetails;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

import javax.servlet.FilterChain;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.http.HttpSession;
import java.io.IOException;

@Component
public class SamlSessionFilter extends OncePerRequestFilter {

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response,
                                     FilterChain filterChain) throws ServletException, IOException {

        Authentication existingAuth = SecurityContextHolder.getContext().getAuthentication();

        if (existingAuth == null || !existingAuth.isAuthenticated() ||
                !(existingAuth.getPrincipal() instanceof SamlUserDetails)) {

            HttpSession session = request.getSession(false);
            if (session != null) {
                SamlUserDetails userDetails = (SamlUserDetails) session.getAttribute("saml_user");
                if (userDetails != null) {
                    Authentication authentication = new UsernamePasswordAuthenticationToken(
                            userDetails, null, userDetails.getAuthorities());
                    SecurityContextHolder.getContext().setAuthentication(authentication);
                }
            }
        }

        filterChain.doFilter(request, response);
    }
}

// === SamlSessionListener.java ===
package com.enterprise.samlsp.listener;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Component;

import javax.servlet.annotation.WebListener;
import javax.servlet.http.HttpSessionEvent;
import javax.servlet.http.HttpSessionListener;

@Component
@WebListener
public class SamlSessionListener implements HttpSessionListener {

    private static final Logger logger = LoggerFactory.getLogger(SamlSessionListener.class);

    @Override
    public void sessionCreated(HttpSessionEvent se) {
        logger.debug("Session created: {}", se.getSession().getId());
    }

    @Override
    public void sessionDestroyed(HttpSessionEvent se) {
        String nameId = (String) se.getSession().getAttribute("saml_name_id");
        logger.info("Session destroyed for user: {}, session: {}", nameId, se.getSession().getId());
    }
}

// === SamlApiController.java (REST API for session data) ===
package com.enterprise.samlsp.controller;

import com.enterprise.samlsp.model.SamlUserDetails;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import javax.servlet.http.HttpSession;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api")
public class SamlApiController {

    @GetMapping("/user")
    public ResponseEntity<Map<String, Object>> getCurrentUser() {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        if (auth != null && auth.getPrincipal() instanceof SamlUserDetails) {
            SamlUserDetails user = (SamlUserDetails) auth.getPrincipal();
            Map<String, Object> userInfo = new HashMap<>();
            userInfo.put("nameId", user.getNameId());
            userInfo.put("email", user.getEmail());
            userInfo.put("firstName", user.getFirstName());
            userInfo.put("lastName", user.getLastName());
            userInfo.put("displayName", user.getDisplayName());
            userInfo.put("department", user.getDepartment());
            userInfo.put("attributes", user.getAttributes());
            userInfo.put("authorities", user.getAuthorities());
            return ResponseEntity.ok(userInfo);
        }
        return ResponseEntity.status(401).build();
    }

    @GetMapping("/session")
    public ResponseEntity<Map<String, Object>> getSessionInfo(HttpSession session) {
        Map<String, Object> sessionInfo = new HashMap<>();
        sessionInfo.put("sessionId", session.getId());
        sessionInfo.put("creationTime", session.getCreationTime());
        sessionInfo.put("lastAccessedTime", session.getLastAccessedTime());
        sessionInfo.put("maxInactiveInterval", session.getMaxInactiveInterval());
        sessionInfo.put("nameId", session.getAttribute("saml_name_id"));
        sessionInfo.put("sessionIndex", session.getAttribute("saml_session_index"));
        return ResponseEntity.ok(sessionInfo);
    }
}

